parameters.jsCode:
const body = $input.first().json.body || $input.first().json;

const alert = {
  type: body.alert_type || 'lead_qualified',
  contact_id: body.contact_id || body.crm_record_id,
  contact_name: body.contact_name || `${body.first_name || ''} ${body.last_name || ''}`.trim(),
  email: body.email,
  phone: body.phone,
  project_id: body.project_id,
  project_name: body.project_name || body.project_id,
  qualification_score: body.qualification_score || 0,
  language: body.language || 'fr',
  deal_value: body.deal_value,
  contract_status: body.contract_status,
  assigned_to: body.assigned_to,
  source_agent: body.source_agent || 'atlas',
  details: body.details || '',
};

// Determine priority
if (alert.qualification_score >= 80 || alert.contract_status === 'awaiting_signature') {
  alert.priority = 'high';
  alert.emoji = '🔥';
} else if (alert.qualification_score >= 60 || alert.contract_status === 'signed') {
  alert.priority = 'medium';
  alert.emoji = '📊';
} else {
  alert.priority = 'low';
  alert.emoji = 'ℹ️';
}

return [{ json: alert }];

